def read_varint(buf, off):
    v=0
    for i in range(9):
        x=buf[off+i]
        if i==8:
            v=(v<<8)|x
            return v, off+i+1
        v=(v<<7)|(x&0x7f)
        if not (x&0x80):
            return v, off+i+1
    raise ValueError

def serial_len(t):
    if t==0:return 0
    if t==1:return 1
    if t==2:return 2
    if t==3:return 3
    if t==4:return 4
    if t==5:return 6
    if t==6:return 8
    if t==7:return 8
    if t==8:return 0
    if t==9:return 0
    if t>=12:
        return (t-12)//2
    raise ValueError(t)

def decode_int(data):
    return int.from_bytes(data,'big',signed=True)

def decode_value(t,data):
    if t==0:return None
    if t in (1,2,3,4,5,6):return decode_int(data)
    if t==7:
        import struct
        return struct.unpack('>d',data)[0]
    if t==8:return 0
    if t==9:return 1
    if t>=12:
        if t%2==0:
            return data
        else:
            try:
                return data.decode('utf-8')
            except:
                return data.decode('latin1')
    return data

